package pe.edu.utp.tmo.controller; import java.util.*; import org.springframework.http.ResponseEntity; import org.springframework.web.bind.annotation.*; import pe.edu.utp.tmo.dto.response.TipificacionResponse; import pe.edu.utp.tmo.service.CatalogService; @RestController @RequestMapping("/api/catalogs") public class CatalogController{ private final CatalogService s; public CatalogController(CatalogService s){this.s=s;} @GetMapping("/tipificaciones") ResponseEntity<List<TipificacionResponse>> tips(){return ResponseEntity.ok(s.listarTipificacionesActivas());}}